import bcrypt from "bcryptjs";
var registerUserInDB = async (payload) => {
  const { name, email, password, profileImg, role, address, phone } = payload;
  const existingUser = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (existingUser) {
    throw new Error("User with this email already exists");
  }
  const hashedPassword = await bcrypt.hash(password, config_default.bcrypt_salt_rounds);
  const newUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashedPassword,
      profileImg,
      role,
      address,
      phone
    }
  });
  const user = await prisma.user.findUnique({
    where: {
      id: newUser.id,
      email: newUser.email || email
    },
    omit: {
      password: true
    }
  });
  return user;
};
var loginUserInDB = async (payload) => {
  const { email, password } = payload;
  const user = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (!user) {
    throw new Error("User not found");
  }
  ;
  if (user.status == "BANNED") {
    throw new Error("Your account is banned");
  }
  const comparePassword = await bcrypt.compare(password, user.password);
  if (!comparePassword) {
    throw new Error("Invalid password");
  }
  ;
  delete user.password;
  const jwtPayload = user;
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  const refreshToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_refresh_secret,
    config_default.jwt_refresh_expires_in
  );
  return {
    user,
    accessToken,
    refreshToken
  };
};
var getMyProfileFromDB = async (userId) => {
  const user = await prisma.user.findUniqueOrThrow({
    where: { id: userId },
    omit: {
      password: true
    }
  });
  return user;
};
var authService = {
  registerUserInDB,
  loginUserInDB,
  getMyProfileFromDB
};

