var updateTechnicianProfileIntoDB = async (technicianId, payload) => {
  const { name, phone, address, profileImg, experience, hourlyRate, ...profileData } = payload;
  return await prisma.$transaction(async (tx) => {
    const userData = {};
    if (name !== void 0) userData.name = name;
    if (phone !== void 0) userData.phone = phone;
    if (address !== void 0) userData.address = address;
    if (profileImg !== void 0) userData.profileImg = profileImg;
    if (Object.keys(userData).length) {
      await tx.user.update({
        where: { id: technicianId },
        data: userData
      });
    }
    const profileUpdateData = { ...profileData };
    if (experience !== void 0) {
      profileUpdateData.experience = Number(experience);
    }
    if (hourlyRate !== void 0) {
      profileUpdateData.hourlyRate = Number(hourlyRate);
    }
    const technicianProfile = await tx.technicianProfile.upsert({
      where: { userId: technicianId },
      update: profileUpdateData,
      create: {
        userId: technicianId,
        ...profileData,
        experience: experience !== void 0 ? Number(experience) : 0,
        hourlyRate: hourlyRate !== void 0 ? Number(hourlyRate) : 0
      }
    });
    return await tx.technicianProfile.findUniqueOrThrow({
      where: { id: technicianProfile.id },
      include: {
        user: {
          select: {
            id: true,
            name: true,
            email: true,
            phone: true,
            address: true,
            role: true,
            status: true,
            profileImg: true
          }
        },
        services: {
          include: {
            category: true
          }
        }
      }
    });
  });
};
var addAvailabilityIntoDB = async (userId, payload) => {
  const technician = await prisma.technicianProfile.findUniqueOrThrow({
    where: { userId }
  });
  const queries = payload.map(
    (slot) => prisma.availability.upsert({
      where: {
        technicianId_dayOfWeek_startTime_endTime: {
          technicianId: technician.id,
          dayOfWeek: slot.dayOfWeek,
          startTime: slot.startTime,
          endTime: slot.endTime
        }
      },
      update: {
        isAvailable: slot.isAvailable
      },
      create: {
        technicianId: technician.id,
        dayOfWeek: slot.dayOfWeek,
        startTime: slot.startTime,
        endTime: slot.endTime,
        isAvailable: slot.isAvailable ?? true
      }
    })
  );
  return await prisma.$transaction(queries);
};
